fn:_generate_md_field_schema(name, field_info:FieldInfo, decorators:DecoratorInfos)->ModelField = 
  _common_field_schema(name, field_info, decorators) |> λ(schema,metadata): 
  model_field(schema, serialization_exclude=field_info.exclude, validation_alias=_convert_to_aliases(field_info.validation_alias), serialization_alias=field_info.serialization_alias, serialization_exclude_if=field_info.exclude_if, frozen=field_info.frozen, metadata=metadata)
